import{_ as n,o as r,c as i,ag as t}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Ihre erste Rechnung","description":"","frontmatter":{},"headers":[],"relativePath":"de/getting-started/first-invoice.md","filePath":"de/getting-started/first-invoice.md"}'),a={name:"de/getting-started/first-invoice.md"};function s(l,e,h,o,u,g){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="ihre-erste-rechnung" tabindex="-1">Ihre erste Rechnung <a class="header-anchor" href="#ihre-erste-rechnung" aria-label="Permalink to &quot;Ihre erste Rechnung&quot;">​</a></h1><p>Diese Anleitung führt Sie durch die Erstellung und den Versand Ihrer ersten Rechnung in MyCompanyDesk.</p><h2 id="bevor-sie-beginnen" tabindex="-1">Bevor Sie beginnen <a class="header-anchor" href="#bevor-sie-beginnen" aria-label="Permalink to &quot;Bevor Sie beginnen&quot;">​</a></h2><p>Stellen Sie sicher, dass Sie:</p><ul><li><a href="/de/getting-started/company-setup">Ihre Unternehmensinformationen eingerichtet</a> haben (Name, Adresse, IBAN)</li><li>Mindestens einen Kunden haben, dem Sie eine Rechnung stellen können (Sie können während des Prozesses einen erstellen)</li></ul><h2 id="rechnung-erstellen" tabindex="-1">Rechnung erstellen <a class="header-anchor" href="#rechnung-erstellen" aria-label="Permalink to &quot;Rechnung erstellen&quot;">​</a></h2><ol><li>Navigieren Sie zu <strong>Rechnungen</strong> in der Seitenleiste</li><li>Klicken Sie auf die Schaltfläche <strong>Neue Rechnung</strong> (oder verwenden Sie den <strong>+</strong>-Schwebenden-Button auf Mobilgeräten)</li><li>Füllen Sie das Rechnungsformular aus:</li></ol><h3 id="kunden-auswahlen" tabindex="-1">Kunden auswählen <a class="header-anchor" href="#kunden-auswahlen" aria-label="Permalink to &quot;Kunden auswählen&quot;">​</a></h3><p>Beginnen Sie mit der Eingabe des Kundennamens. Wenn der Kunde existiert, wählen Sie ihn aus der Dropdown-Liste aus. Wenn nicht, klicken Sie auf <strong>Neuen Kunden erstellen</strong>, um ihn direkt hinzuzufügen.</p><h3 id="positionen-hinzufugen" tabindex="-1">Positionen hinzufügen <a class="header-anchor" href="#positionen-hinzufugen" aria-label="Permalink to &quot;Positionen hinzufügen&quot;">​</a></h3><p>Jede Position enthält:</p><ul><li><strong>Beschreibung</strong> — Wofür Sie abrechnen</li><li><strong>Menge</strong> — Anzahl der Einheiten</li><li><strong>Einzelpreis</strong> — Preis pro Einheit</li><li><strong>USt.-Satz</strong> — Anwendbarer USt.-Prozentsatz (0 %, 9 %, 21 % usw.)</li></ul><p>Klicken Sie auf <strong>Position hinzufügen</strong>, um weitere Positionen hinzuzufügen. Die Gesamtsumme wird automatisch inklusive USt. berechnet.</p><h3 id="rechnungsdetails-festlegen" tabindex="-1">Rechnungsdetails festlegen <a class="header-anchor" href="#rechnungsdetails-festlegen" aria-label="Permalink to &quot;Rechnungsdetails festlegen&quot;">​</a></h3><ul><li><strong>Rechnungsnummer</strong> — Automatisch generiert basierend auf Ihren Nummerierungseinstellungen</li><li><strong>Rechnungsdatum</strong> — Standardmäßig heute</li><li><strong>Fälligkeitsdatum</strong> — Berechnet aus Ihren Standard-Zahlungsbedingungen (anpassbar)</li><li><strong>Anmerkungen</strong> — Optionale Anmerkungen, die auf der Rechnung erscheinen</li></ul><h3 id="speichern" tabindex="-1">Speichern <a class="header-anchor" href="#speichern" aria-label="Permalink to &quot;Speichern&quot;">​</a></h3><p>Klicken Sie auf <strong>Speichern</strong>, um die Rechnung als <strong>Entwurf</strong> zu erstellen. Sie können vor dem Versand noch alles bearbeiten.</p><h2 id="rechnung-in-der-vorschau-anzeigen" tabindex="-1">Rechnung in der Vorschau anzeigen <a class="header-anchor" href="#rechnung-in-der-vorschau-anzeigen" aria-label="Permalink to &quot;Rechnung in der Vorschau anzeigen&quot;">​</a></h2><p>Vor dem Versand können Sie eine Vorschau ansehen, wie die PDF aussehen wird:</p><ol><li>Öffnen Sie die Rechnungsdetailseite</li><li>Klicken Sie auf <strong>Vorschau</strong>, um die generierte PDF zu sehen</li><li>Überprüfen Sie, ob alle Informationen korrekt sind — Firmendaten, Kundeninformationen, Positionen, Gesamtbeträge</li></ol><h2 id="rechnung-versenden" tabindex="-1">Rechnung versenden <a class="header-anchor" href="#rechnung-versenden" aria-label="Permalink to &quot;Rechnung versenden&quot;">​</a></h2><p>Wenn Sie bereit sind zum Versenden:</p><ol><li>Klicken Sie auf <strong>Senden</strong> auf der Rechnungsdetailseite</li><li>Überprüfen Sie die E-Mail, die an Ihren Kunden gesendet wird: <ul><li>Betreffzeile (anpassbar)</li><li>E-Mail-Text (basierend auf Ihrer E-Mail-Vorlage)</li><li>PDF-Anhang</li><li>Zahlungslink (falls aktiviert)</li></ul></li><li>Klicken Sie auf <strong>Senden</strong>, um die Rechnung zuzustellen</li></ol><p>Der Rechnungsstatus ändert sich von <strong>Entwurf</strong> zu <strong>Gesendet</strong>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Sie können Ihre E-Mail-Vorlagen unter <strong>Einstellungen &gt; E-Mail</strong> anpassen. Vorlagen unterstützen Ihr Branding und können pro Sprache eingestellt werden.</p></div><h2 id="zahlung-verfolgen" tabindex="-1">Zahlung verfolgen <a class="header-anchor" href="#zahlung-verfolgen" aria-label="Permalink to &quot;Zahlung verfolgen&quot;">​</a></h2><p>Nach dem Versand erscheint die Rechnung in Ihren Ansichten <strong>Gesendet</strong> oder <strong>Überfällig</strong>. Wenn der Kunde zahlt:</p><ul><li>Wenn der Kunde über den <strong>Zahlungslink</strong> zahlt, wird die Rechnung automatisch als bezahlt markiert</li><li>Bei Banküberweisungen klicken Sie auf <strong>Als bezahlt markieren</strong> auf der Rechnung, um die Zahlung manuell zu erfassen</li></ul><h2 id="rechnungsstatus" tabindex="-1">Rechnungsstatus <a class="header-anchor" href="#rechnungsstatus" aria-label="Permalink to &quot;Rechnungsstatus&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Entwurf</strong></td><td>Erstellt, aber noch nicht gesendet. Vollständig bearbeitbar.</td></tr><tr><td><strong>Gesendet</strong></td><td>An den Kunden zugestellt. Warten auf Zahlung.</td></tr><tr><td><strong>Überfällig</strong></td><td>Fälligkeitsdatum überschritten und noch unbezahlt.</td></tr><tr><td><strong>Bezahlt</strong></td><td>Zahlung eingegangen und bestätigt.</td></tr><tr><td><strong>Storniert</strong></td><td>Rechnung wurde storniert. Keine Zahlung erwartet.</td></tr></tbody></table><h2 id="schnellerfassung" tabindex="-1">Schnellerfassung <a class="header-anchor" href="#schnellerfassung" aria-label="Permalink to &quot;Schnellerfassung&quot;">​</a></h2><p>Für eine schnellere Rechnungserstellung verwenden Sie die <strong>Schnellerfassung</strong>:</p><ol><li>Klicken Sie auf das Schnellerfassungs-Symbol auf der Rechnungsliste</li><li>Wählen Sie einen Kunden</li><li>Fügen Sie Positionen hinzu (oder verwenden Sie eine gespeicherte Vorlage)</li><li>Speichern und optional sofort versenden</li></ol><p>Die Schnellerfassung ist ideal für Routinerechnungen, bei denen Sie regelmäßig ähnliche Positionen abrechnen.</p><h2 id="vorlagen-verwenden" tabindex="-1">Vorlagen verwenden <a class="header-anchor" href="#vorlagen-verwenden" aria-label="Permalink to &quot;Vorlagen verwenden&quot;">​</a></h2><p>Sparen Sie Zeit mit Rechnungsvorlagen:</p><ol><li>Erstellen Sie eine Rechnung mit Ihren häufig verwendeten Positionen</li><li>Klicken Sie auf <strong>Als Vorlage speichern</strong></li><li>Beim nächsten Mal starten Sie eine neue Rechnung aus der Vorlage — alle Positionen sind vorausgefüllt</li></ol><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Herzlichen Glückwunsch zum Versand Ihrer ersten Rechnung! Entdecken Sie weitere Funktionen:</p><ul><li><a href="/de/features/expenses">Ausgaben verfolgen</a></li><li><a href="/de/features/quotes">Angebote erstellen</a> für potenzielle Aufträge</li><li><a href="/de/features/recurring-invoices">Wiederkehrende Rechnungen einrichten</a> für regelmäßige Abrechnungen</li><li><a href="/de/features/reports">Berichte anzeigen</a>, um Ihre Finanzen zu verstehen</li></ul>',40)])])}const f=n(a,[["render",s]]);export{c as __pageData,f as default};
